package com.example.hybridapp

import android.content.Context
import android.content.SharedPreferences
import android.util.Log
import android.webkit.JavascriptInterface
import org.json.JSONObject

class NativeBridge(
    private val context: Context,
    private val cameraCallback: () -> Unit,
    private val notificationCallback: (Boolean) -> Unit,
    private val jsEvaluator: (String) -> Unit
) {
    companion object {
        const val BRIDGE_NAME = "NativeBridge"
        private const val TAG = "NativeBridge"
        private const val PREFS_NAME = "hybrid_app_storage"
    }

    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    // ---- Camera Access ----

    @JavascriptInterface
    fun openCamera() {
        Log.d(TAG, "openCamera called from JavaScript")
        cameraCallback()
    }

    @JavascriptInterface
    fun isCameraAvailable(): Boolean {
        val pm = context.packageManager
        return pm.hasSystemFeature(android.content.pm.PackageManager.FEATURE_CAMERA_ANY)
    }

    // ---- Local Storage ----

    @JavascriptInterface
    fun setItem(key: String, value: String) {
        Log.d(TAG, "setItem: $key = $value")
        sharedPreferences.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getItem(key: String): String? {
        val value = sharedPreferences.getString(key, null)
        Log.d(TAG, "getItem: $key = $value")
        return value
    }

    @JavascriptInterface
    fun removeItem(key: String) {
        Log.d(TAG, "removeItem: $key")
        sharedPreferences.edit().remove(key).apply()
    }

    @JavascriptInterface
    fun clear() {
        Log.d(TAG, "clear all items")
        sharedPreferences.edit().clear().apply()
    }

    @JavascriptInterface
    fun getAllKeys(): String {
        val keys = sharedPreferences.all.keys
        val jsonArray = org.json.JSONArray(keys.toList())
        return jsonArray.toString()
    }

    @JavascriptInterface
    fun setItemSecure(key: String, value: String) {
        // In production, use EncryptedSharedPreferences
        val securePrefs = context.getSharedPreferences("${PREFS_NAME}_secure", Context.MODE_PRIVATE)
        securePrefs.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getItemSecure(key: String): String? {
        val securePrefs = context.getSharedPreferences("${PREFS_NAME}_secure", Context.MODE_PRIVATE)
        return securePrefs.getString(key, null)
    }

    // ---- Push Notifications ----

    @JavascriptInterface
    fun requestNotificationPermission() {
        Log.d(TAG, "requestNotificationPermission called from JavaScript")
        notificationCallback(true)
    }

    @JavascriptInterface
    fun getPushToken(): String? {
        return sharedPreferences.getString("fcm_token", null)
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String) {
        Log.d(TAG, "subscribeToPushTopic: $topic")
        com.google.firebase.messaging.FirebaseMessaging.getInstance()
            .subscribeToTopic(topic)
            .addOnCompleteListener { task ->
                val result = JSONObject().apply {
                    put("topic", topic)
                    put("success", task.isSuccessful)
                }
                jsEvaluator("javascript:window.onTopicSubscribed && window.onTopicSubscribed(${result})")
            }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String) {
        Log.d(TAG, "unsubscribeFromPushTopic: $topic")
        com.google.firebase.messaging.FirebaseMessaging.getInstance()
            .unsubscribeFromTopic(topic)
            .addOnCompleteListener { task ->
                val result = JSONObject().apply {
                    put("topic", topic)
                    put("success", task.isSuccessful)
                }
                jsEvaluator("javascript:window.onTopicUnsubscribed && window.onTopicUnsubscribed(${result})")
            }
    }

    // ---- Device Info ----

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val info = JSONObject().apply {
            put("platform", "android")
            put("model", android.os.Build.MODEL)
            put("manufacturer", android.os.Build.MANUFACTURER)
            put("sdkVersion", android.os.Build.VERSION.SDK_INT)
            put("appVersion", getAppVersion())
        }
        return info.toString()
    }

    @JavascriptInterface
    fun getAppVersion(): String {
        return try {
            val pInfo = context.packageManager.getPackageInfo(context.packageName, 0)
            pInfo.versionName ?: "unknown"
        } catch (e: Exception) {
            "unknown"
        }
    }

    // ---- Utility ----

    @JavascriptInterface
    fun showToast(message: String) {
        android.widget.Toast.makeText(context, message, android.widget.Toast.LENGTH_SHORT).show()
    }

    @JavascriptInterface
    fun vibrate(milliseconds: Long) {
        val vibrator = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.S) {
            val vibratorManager = context.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as android.os.VibratorManager
            vibratorManager.defaultVibrator
        } else {
            @Suppress("DEPRECATION")
            context.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
        }

        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            vibrator.vibrate(
                android.os.VibrationEffect.createOneShot(milliseconds, android.os.VibrationEffect.DEFAULT_AMPLITUDE)
            )
        } else {
            @Suppress("DEPRECATION")
            vibrator.vibrate(milliseconds)
        }
    }

    @JavascriptInterface
    fun shareContent(title: String, text: String, url: String) {
        val shareIntent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
            type = "text/plain"
            putExtra(android.content.Intent.EXTRA_SUBJECT, title)
            putExtra(android.content.Intent.EXTRA_TEXT, "$text\n$url")
        }
        val chooser = android.content.Intent.createChooser(shareIntent, title)
        chooser.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
        context.startActivity(chooser)
    }

    @JavascriptInterface
    fun log(level: String, message: String) {
        when (level.lowercase()) {
            "debug" -> Log.d(TAG, "JS: $message")
            "info" -> Log.i(TAG, "JS: $message")
            "warn" -> Log.w(TAG, "JS: $message")
            "error" -> Log.e(TAG, "JS: $message")
            else -> Log.v(TAG, "JS: $message")
        }
    }
}

