package com.example.hybridapp

import android.Manifest
import android.annotation.SuppressLint
import android.app.Activity
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.os.Environment
import android.provider.MediaStore
import android.util.Log
import android.view.KeyEvent
import android.view.View
import android.webkit.*
import android.widget.FrameLayout
import android.widget.ProgressBar
import android.widget.Toast
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import androidx.swiperefreshlayout.widget.SwipeRefreshLayout
import com.google.firebase.messaging.FirebaseMessaging
import org.json.JSONObject
import java.io.File
import java.text.SimpleDateFormat
import java.util.*

class MainActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "MainActivity"
        private const val WEB_APP_URL = "https://your-web-app-url.com"
        private const val CAMERA_PERMISSION_REQUEST = 100
        private const val NOTIFICATION_PERMISSION_REQUEST = 101
    }

    private lateinit var webView: WebView
    private lateinit var progressBar: ProgressBar
    private lateinit var nativeBridge: NativeBridge

    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null
    private var cameraImageUri: Uri? = null

    private lateinit var cameraLauncher: ActivityResultLauncher<Intent>
    private lateinit var fileChooserLauncher: ActivityResultLauncher<Intent>
    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var notificationPermissionLauncher: ActivityResultLauncher<String>

    // For fullscreen video support
    private var customView: View? = null
    private var customViewCallback: WebChromeClient.CustomViewCallback? = null
    private lateinit var fullscreenContainer: FrameLayout

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        initViews()
        registerActivityResultLaunchers()
        setupWebView()
        setupNativeBridge()
        initFirebaseMessaging()

        if (savedInstanceState != null) {
            webView.restoreState(savedInstanceState)
        } else {
            webView.loadUrl(WEB_APP_URL)
        }

        handlePushNotificationIntent(intent)
    }

    private fun initViews() {
        webView = findViewById(R.id.webView)
        progressBar = findViewById(R.id.progressBar)
        fullscreenContainer = findViewById(R.id.fullscreenContainer)
    }

    private fun registerActivityResultLaunchers() {
        cameraLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                cameraImageUri?.let { uri ->
                    val jsCallback = "javascript:window.onCameraResult && window.onCameraResult('${uri}')"
                    webView.evaluateJavascript(jsCallback, null)
                }
                // Also handle file upload callback if active
                fileUploadCallback?.let { callback ->
                    cameraImageUri?.let { uri ->
                        callback.onReceiveValue(arrayOf(uri))
                    } ?: callback.onReceiveValue(null)
                    fileUploadCallback = null
                }
            } else {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = null
                webView.evaluateJavascript(
                    "javascript:window.onCameraError && window.onCameraError('Camera cancelled')", null
                )
            }
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                val results = if (data?.clipData != null) {
                    val count = data.clipData!!.itemCount
                    Array(count) { i -> data.clipData!!.getItemAt(i).uri }
                } else {
                    data?.data?.let { arrayOf(it) }
                }
                fileUploadCallback?.onReceiveValue(results)
            } else {
                fileUploadCallback?.onReceiveValue(null)
            }
            fileUploadCallback = null
        }

        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            if (isGranted) {
                launchCamera()
            } else {
                Toast.makeText(this, "Camera permission is required", Toast.LENGTH_SHORT).show()
                webView.evaluateJavascript(
                    "javascript:window.onCameraError && window.onCameraError('Permission denied')", null
                )
            }
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            val result = JSONObject().apply {
                put("granted", isGranted)
            }
            webView.evaluateJavascript(
                "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult($result)",
                null
            )
            if (isGranted) {
                fetchAndSendFcmToken()
            }
        }
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            loadWithOverviewMode = true
            useWideViewPort = true
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
            mediaPlaybackRequiresUserGesture = false
            mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
            cacheMode = WebSettings.LOAD_DEFAULT

            // Enable geolocation
            setGeolocationEnabled(true)

            // User agent customization
            userAgentString = "$userAgentString HybridApp/1.0"
        }

        webView.webViewClient = object : WebViewClient() {
            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
                progressBar.visibility = View.VISIBLE
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                progressBar.visibility = View.GONE
                injectBridgeReadyEvent()
            }

            override fun onReceivedError(
                view: WebView?,
                request: WebResourceRequest?,
                error: WebResourceError?
            ) {
                super.onReceivedError(view, request, error)
                if (request?.isForMainFrame == true) {
                    Log.e(TAG, "WebView error: ${error?.description}")
                    loadErrorPage()
                }
            }

            override fun shouldOverrideUrlLoading(
                view: WebView?,
                request: WebResourceRequest?
            ): Boolean {
                val url = request?.url?.toString() ?: return false

                // Handle external links
                return when {
                    url.startsWith("tel:") || url.startsWith("mailto:") ||
                            url.startsWith("sms:") || url.startsWith("geo:") -> {
                        startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(url)))
                        true
                    }
                    url.startsWith("intent://") -> {
                        try {
                            val intent = Intent.parseUri(url, Intent.URI_INTENT_SCHEME)
                            startActivity(intent)
                        } catch (e: Exception) {
                            Log.e(TAG, "Failed to handle intent URL", e)
                        }
                        true
                    }
                    !url.startsWith(WEB_APP_URL) && (url.startsWith("http://") || url.startsWith("https://")) -> {
                        // Open external URLs in browser
                        startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(url)))
                        true
                    }
                    else -> false
                }
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onProgressChanged(view: WebView?, newProgress: Int) {
                progressBar.progress = newProgress
                if (newProgress == 100) {
                    progressBar.visibility = View.GONE
                }
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = filePathCallback

                val acceptTypes = fileChooserParams?.acceptTypes ?: arrayOf()
                val isCapture = fileChooserParams?.isCaptureEnabled ?: false

                if (isCapture && acceptTypes.any { it.startsWith("image") }) {
                    openCameraWithPermissionCheck()
                    return true
                }

                val intent = fileChooserParams?.createIntent()
                if (intent != null) {
                    try {
                        // Create chooser with camera option
                        val chooserIntent = createFileChooserIntent(intent, acceptTypes)
                        fileChooserLauncher.launch(chooserIntent)
                    } catch (e: Exception) {
                        fileUploadCallback = null
                        return false
                    }
                }
                return true
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.let {
                    runOnUiThread {
                        it.grant(it.resources)
                    }
                }
            }

            override fun onGeolocationPermissionsShowPrompt(
                origin: String?,
                callback: GeolocationPermissions.Callback?
            ) {
                callback?.invoke(origin, true, false)
            }

            // Fullscreen video support
            override fun onShowCustomView(view: View?, callback: CustomViewCallback?) {
                customView = view
                customViewCallback = callback
                fullscreenContainer.addView(view)
                fullscreenContainer.visibility = View.VISIBLE
                webView.visibility = View.GONE
            }

            override fun onHideCustomView() {
                fullscreenContainer.removeAllViews()
                fullscreenContainer.visibility = View.GONE
                webView.visibility = View.VISIBLE
                customViewCallback?.onCustomViewHidden()
                customView = null
                customViewCallback = null
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                consoleMessage?.let {
                    Log.d(TAG, "Console: ${it.message()} [${it.sourceId()}:${it.lineNumber()}]")
                }
                return true
            }

            override fun onJsAlert(
                view: WebView?,
                url: String?,
                message: String?,
                result: JsResult?
            ): Boolean {
                AlertDialog.Builder(this@MainActivity)
                    .setMessage(message)
                    .setPositiveButton("OK") { _, _ -> result?.confirm() }
                    .setCancelable(false)
                    .show()
                return true
            }

            override fun onJsConfirm(
                view: WebView?,
                url: String?,
                message: String?,
                result: JsResult?
            ): Boolean {
                AlertDialog.Builder(this@MainActivity)
                    .setMessage(message)
                    .setPositiveButton("OK") { _, _ -> result?.confirm() }
                    .setNegativeButton("Cancel") { _, _ -> result?.cancel() }
                    .setCancelable(false)
                    .show()
                return true
            }
        }
    }

    private fun setupNativeBridge() {
        nativeBridge = NativeBridge(
            context = this,
            cameraCallback = { openCameraWithPermissionCheck() },
            notificationCallback = { requestNotificationPermission() },
            jsEvaluator = { script ->
                runOnUiThread {
                    webView.evaluateJavascript(script, null)
                }
            }
        )
        webView.addJavascriptInterface(nativeBridge, NativeBridge.BRIDGE_NAME)
    }

    private fun injectBridgeReadyEvent() {
        val js = """
            (function() {
                if (window.NativeBridge) {
                    var event = new CustomEvent('nativeBridgeReady', { 
                        detail: { platform: 'android' } 
                    });
                    window.dispatchEvent(event);
                    console.log('NativeBridge is ready');
                }
            })();
        """.trimIndent()
        webView.evaluateJavascript(js, null)
    }

    // ---- Camera ----

    private fun openCameraWithPermissionCheck() {
        when {
            ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) ==
                    PackageManager.PERMISSION_GRANTED -> {
                launchCamera()
            }
            ActivityCompat.shouldShowRequestPermissionRationale(this, Manifest.permission.CAMERA) -> {
                AlertDialog.Builder(this)
                    .setTitle("Camera Permission")
                    .setMessage("This app needs camera access to take photos.")
                    .setPositiveButton("Grant") { _, _ ->
                        cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                    }
                    .setNegativeButton("Deny") { _, _ ->
                        webView.evaluateJavascript(
                            "javascript:window.onCameraError && window.onCameraError('Permission denied')",
                            null
                        )
                    }
                    .show()
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }

    private fun launchCamera() {
        val photoFile = createImageFile()
        cameraImageUri = FileProvider.getUriForFile(
            this,
            "${packageName}.fileprovider",
            photoFile
        )
        val cameraIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
        }
        cameraLauncher.launch(cameraIntent)
    }

    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
        val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
        return File.createTempFile("IMG_${timeStamp}_", ".jpg", storageDir)
    }

    private fun createFileChooserIntent(baseIntent: Intent, acceptTypes: Array<String>): Intent {
        val intents = mutableListOf<Intent>()

        // Add camera intent if image is accepted
        if (acceptTypes.isEmpty() || acceptTypes.any { it.startsWith("image") || it == "*/*" }) {
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) ==
                PackageManager.PERMISSION_GRANTED
            ) {
                val photoFile = createImageFile()
                cameraImageUri = FileProvider.getUriForFile(this, "${packageName}.fileprovider", photoFile)
                val cameraIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                    putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
                }
                intents.add(cameraIntent)
            }
        }

        val chooserIntent = Intent.createChooser(baseIntent, "Select")
        if (intents.isNotEmpty()) {
            chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, intents.toTypedArray())
        }
        return chooserIntent
    }

    // ---- Push Notifications ----

    private fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            when {
                ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) ==
                        PackageManager.PERMISSION_GRANTED -> {
                    val result = JSONObject().apply { put("granted", true) }
                    webView.evaluateJavascript(
                        "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult($result)",
                        null
                    )
                    fetchAndSendFcmToken()
                }
                else -> {
                    notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                }
            }
        } else {
            val result = JSONObject().apply { put("granted", true) }
            webView.evaluateJavascript(
                "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult($result)",
                null
            )
            fetchAndSendFcmToken()
        }
    }

    private fun initFirebaseMessaging() {
        fetchAndSendFcmToken()
    }

    private fun fetchAndSendFcmToken() {
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (task.isSuccessful) {
                val token = task.result
                Log.d(TAG, "FCM Token: $token")

                // Save token locally
                val prefs = getSharedPreferences("hybrid_app_storage", MODE_PRIVATE)
                prefs.edit().putString("fcm_token", token).apply()

                // Send token to web app
                runOnUiThread {
                    val result = JSONObject().apply { put("token", token) }
                    webView.evaluateJavascript(
                        "javascript:window.onPushTokenReceived && window.onPushTokenReceived($result)",
                        null
                    )
                }
            } else {
                Log.e(TAG, "Failed to get FCM token", task.exception)
            }
        }
    }

    private fun handlePushNotificationIntent(intent: Intent?) {
        intent?.extras?.let { extras ->
            val notificationData = JSONObject()
            for (key in extras.keySet()) {
                notificationData.put(key, extras.getString(key))
            }
            if (notificationData.length() > 0) {
                webView.post {
                    webView.evaluateJavascript(
                        "javascript:window.onPushNotificationReceived && window.onPushNotificationReceived($notificationData)",
                        null
                    )
                }
            }
        }
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        handlePushNotificationIntent(intent)
    }

    // ---- Error Page ----

    private fun loadErrorPage() {
        val errorHtml = """
            <!DOCTYPE html>
            <html>
            <head>
                <meta name="viewport" content="width=device-width, initial-scale=1.0">
                <style>
                    body { 
                        font-family: -apple-system, BlinkMacSystemFont, sans-serif;
                        display: flex; flex-direction: column; align-items: center; 
                        justify-content: center; height: 100vh; margin: 0;
                        background: #f5f5f5; color: #333;
                    }
                    h2 { margin-bottom: 8px; }
                    p { color: #666; margin-bottom: 24px; }
                    button { 
                        background: #2196F3; color: white; border: none;
                        padding: 12px 32px; border-radius: 8px; font-size: 16px;
                        cursor: pointer;
                    }
                </style>
            </head>
            <body>
                <h2>Connection Error</h2>
                <p>Unable to load the app. Please check your internet connection.</p>
                <button onclick="window.location.reload()">Retry</button>
            </body>
            </html>
        """.trimIndent()
        webView.loadDataWithBaseURL(null, errorHtml, "text/html", "UTF-8", null)
    }

    // ---- Lifecycle ----

    override fun onSaveInstanceState(outState: Bundle) {
        super.onSaveInstanceState(outState)
        webView.saveState(outState)
    }

    override fun onResume() {
        super.onResume()
        webView.onResume()
        webView.evaluateJavascript(
            "javascript:window.onAppResumed && window.onAppResumed()", null
        )
    }

    override fun onPause() {
        webView.onPause()
        webView.evaluateJavascript(
            "javascript:window.onAppPaused && window.onAppPaused()", null
        )
        super.onPause()
    }

    override fun onDestroy() {
        webView.destroy()
        super.onDestroy()
    }

    override fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {
        if (keyCode == KeyEvent.KEYCODE_BACK) {
            // Handle fullscreen video back
            if (customView != null) {
                webView.webChromeClient?.onHideCustomView()
                return true
            }
            // Handle WebView back navigation
            if (webView.canGoBack()) {
                webView.goBack()
                return true
            }
        }
        return super.onKeyDown(keyCode, event)
    }
}

